def twos_complement(val, num_bits):
    min_val = -(1 << (num_bits - 1))
    max_val = (1 << (num_bits - 1)) - 1

    if not (min_val <= val <= max_val):
        raise ValueError(f"Value {val} is out of range for {num_bits} bits. "
                         f"Range: [{min_val}, {max_val}]")

    if val >= 0:
        return bin(val)[2:].zfill(num_bits)
    else:
        return bin((1 << num_bits) + val)[2:]
